#include<bits/stdc++.h>
using namespace std;
int main(void){
    queue<char> n;
	map<char,char>kj;
	vector<string> ve;
	char a[2005];
	int w;string s,b;
	bool isyes=false;
	cin>>a>>b>>w;
	kj['1']='1';
	kj['2']='4';kj['3']='9';
	kj['4']='6';kj['5']='5';
	kj['6']='6';kj['7']='9';
	kj['8']='4';kj['9']='1';
	for(int i=strlen(a)-1;i>=0;i--){
		n.push(a[i]);
	}
	for(int i=0;i<w;i++){
		int x=n.front();
		if(x!='0')n.push(kj[x]);
		n.pop();s="";
		for(int j=0;j<n.size();j++){
			n.push(n.front());
			s+=n.front();
			n.pop();
		}
		for(int j=0;j<s.size()/2;j++){
			swap(s[j],s[s.size()-1-j]);
		}
		ve.push_back(s);
		if(s==b){
			isyes=true;
			break;
		}
	}
	if(isyes){
		for(int i=0;i<ve.size();i++){
			cout<<ve[i]<<endl;
		}
	}else{
		cout<<-1;
	}
    return false;
}
